    52→func TestGitHubFetchNewReleases(t *testing.T) {
    53→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    54→		w.Header().Set("Content-Type", "application/json")
    55→		w.Write([]byte(sampleGitHubReleases))
    56→	}))
    57→	defer srv.Close()
    58→
    59→	src := NewGitHubSource(srv.Client(), "ethereum/go-ethereum", "src-id")
    60→	src.baseURL = srv.URL
    61→
    62→	results, err := src.FetchNewReleases(context.Background())
    63→	if err != nil {
    64→		t.Fatalf("FetchNewReleases: %v", err)
    65→	}
    66→
    67→	// Draft should be excluded, so 3 results (v1.17.0, v1.17.0-rc.1, v1.16.9)
    68→	if len(results) != 3 {
    69→		t.Fatalf("got %d results, want 3", len(results))
    70→	}
    71→
    72→	// First entry — stable release
    73→	if results[0].RawVersion != "v1.17.0" {
    74→		t.Errorf("results[0].RawVersion = %q, want %q", results[0].RawVersion, "v1.17.0")
    75→	}
    76→	if results[0].Repository != "ethereum/go-ethereum" {
    77→		t.Errorf("results[0].Repository = %q, want %q", results[0].Repository, "ethereum/go-ethereum")
    78→	}
    79→	if results[0].Changelog == "" {
    80→		t.Error("results[0].Changelog should not be empty")
    81→	}
    82→	if results[0].Timestamp.IsZero() {
    83→		t.Error("results[0].Timestamp should not be zero")
    84→	}
    85→	if results[0].Metadata["prerelease"] != "false" {
    86→		t.Errorf("results[0].Metadata[prerelease] = %q, want %q", results[0].Metadata["prerelease"], "false")
    87→	}
    88→	if results[0].Metadata["release_url"] == "" {
    89→		t.Error("results[0].Metadata[release_url] should not be empty")
    90→	}
    91→
    92→	// Second entry — prerelease
    93→	if results[1].RawVersion != "v1.17.0-rc.1" {
    94→		t.Errorf("results[1].RawVersion = %q, want %q", results[1].RawVersion, "v1.17.0-rc.1")
    95→	}
    96→	if results[1].Metadata["prerelease"] != "true" {
    97→		t.Errorf("results[1].Metadata[prerelease] = %q, want %q", results[1].Metadata["prerelease"], "true")
    98→	}
    99→
   100→	// Third entry
   101→	if results[2].RawVersion != "v1.16.9" {
   102→		t.Errorf("results[2].RawVersion = %q, want %q", results[2].RawVersion, "v1.16.9")
   103→	}
   104→}
