    40→    case "dockerhub":
    41→      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    42→    case "ecr-public":
    43→      return `https://gallery.ecr.aws/${repository}`;
    44→    case "gitlab":
    45→      return `https://gitlab.com/${repository}/-/releases/${version}`;
    46→    default:
    47→      return null;
    48→  }
    49→}
